// Художественный пилот для ступени 8-10 лет.
// Цель: меньше черчения, больше настроения, цветового пятна и законченной мини-работы.

const VIEW = '0 0 300 210';

function step(hint, layer) {
  return { hint, layer };
}

function paper(fill = '#fffaf0') {
  return `<path d="M0 0 H300 V210 H0 Z" fill="${fill}"/>`;
}

function lesson(day, index, data) {
  const level = index < 3 ? 1 : index < 7 ? 2 : 3;
  return {
    slug: `art810-d${String(day).padStart(2, '0')}-${String(index + 1).padStart(2, '0')}-${data.slug}`,
    ageBand: '8-10',
    level,
    title: data.title,
    theme: data.theme,
    chapter: data.chapter,
    skill: data.skill,
    kind: data.kind ?? (level === 3 ? 'combo' : level === 2 ? 'fantasy' : 'draw'),
    order: day * 100 + index + 1,
    free: true,
    cover: data.cover,
    viewBox: VIEW,
    coloredViewBox: VIEW,
    canvas: 'landscape',
    palette: data.palette,
    intro: data.intro,
    steps: data.steps,
    coloredPreview: data.preview,
    storyStageLabel: level === 1 ? 'точный контур' : level === 2 ? 'приём и фактура' : 'мини-картина',
    storyPrompt: data.storyPrompt,
    storyMissions: data.storyMissions,
    colorHint: data.colorHint,
    finishIdea: data.finishIdea,
    parentNote: data.parentNote,
  };
}

