const artPilotRefinements = {
};
function refineArtPilotLesson(lessonItem) {
  const changes = artPilotRefinements[lessonItem.slug];
  return changes ? { ...lessonItem, ...changes } : lessonItem;
}

export const eightTenArtPilotLessons = [...day1, ...day2, ...day3, ...day4, ...day5].map(refineArtPilotLesson);

