export function applyEightTenArtPilot(drawingLessons, drawingChapterGuides) {
  for (const [chapter, guide] of Object.entries(eightTenArtPilotGuides)) {
    drawingChapterGuides[chapter] = guide;
  }

  drawingLessons.splice(
    0,
    drawingLessons.length,
    ...drawingLessons.filter((lessonItem) => lessonItem.ageBand !== '8-10'),
    ...eightTenArtPilotLessons
  );
}
